class Solution {
public:
    int countNumbers(string l, string r, int b) {
        const int MOD = 1e9 + 7;
        function<long long(string)> toDec = [&](string s) {
            long long res = 0;
            for (char c : s) {
                res = res * b + (c - '0');
            }
            return res;
        };

        function<bool(string)> check = [&](string s) {
            int prev = -1;
            for (char c : s) {
                int cur = c - '0';
                if (cur > prev && prev != -1) {
                    continue;
                } else if (cur < prev) {
                    return false;
                }
                prev = cur;
            }
            return true;
        };

        long long L = toDec(l), R = toDec(r);
        long long res = 0;
        for (long long i = L; i <= R; ++i) {
            string num;
            long long tmp = i;
            while (tmp) {
                num.push_back('0' + tmp % b);
                tmp /= b;
            }
            reverse(num.begin(), num.end());
            if (check(num)) ++res;
        }
        return res % MOD;
    }
};
```
